using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace ShoppingCart.Tests;

[TestClass]
public class ShoppingCartTests
{
    private Store.ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new Store.ShoppingCart();

    // --- Adding items ---

    [TestMethod]
    public void AddItem_SingleItem_CalculatesTotalCorrectly()
    {
        _cart.AddItem("SKU1", 2, 10.00m);
        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_SumsAll()
    {
        _cart.AddItem("A", 1, 5.00m);
        _cart.AddItem("B", 3, 2.50m);
        Assert.AreEqual(12.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_AccumulatesQuantity()
    {
        _cart.AddItem("SKU1", 1, 10.00m);
        _cart.AddItem("SKU1", 2, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU1", 0, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU1", -1, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU1", 1, -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 5.00m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREE", 3, 0m);
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // --- Removing items ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 5.00m);
        _cart.RemoveItem("A");
        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentItem_Throws()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("NOPE"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // --- Coupons ---

    [TestMethod]
    public void ApplyCoupon_Save10_Gives10PercentOff()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Gives20PercentOff()
    {
        _cart.AddItem("A", 2, 50.00m);
        _cart.ApplyCoupon("SAVE20");
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("save10");
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalStaysZero()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }
}

